mapper.delete:
DELETE FROM TBL_SCRIPTS
WHERE MY_BUILD_ID = #{myBuildId}
  AND OPP_BUILD_ID = #{oppBuildId}

mapper.select:
SELECT SCRIPT_ID, MY_BUILD_ID, OPP_BUILD_ID, RESULT, CONTENT, CREATED_AT
FROM TBL_SCRIPTS
WHERE MY_BUILD_ID  = #{myBuildId}
  AND OPP_BUILD_ID = #{oppBuildId}
ORDER BY RESULT

SELECT SCRIPT_ID, MY_BUILD_ID, OPP_BUILD_ID, RESULT, CONTENT
FROM TBL_SCRIPTS
WHERE MY_BUILD_ID  = #{myBuildId}
  AND OPP_BUILD_ID = #{oppBuildId}
  AND RESULT        = #{result}
ORDER BY SCRIPT_ID

SELECT MATCHUP
FROM TBL_BUILD_MATCHUP
WHERE BUILD_ID_A = #{myBuildId} AND BUILD_ID_B = #{oppBuildId}
